import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { FiCreditCard, FiDollarSign, FiSmartphone, FiCheck } from 'react-icons/fi';
import { useCart } from '../../context/CartContext';
import { useAuth } from '../../context/AuthContext';
import api from '../../services/api';
import toast from 'react-hot-toast';

const Checkout = () => {
  const { cart, getCartTotal, clearCart } = useCart();
  const { user } = useAuth();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [formData, setFormData] = useState({
    orderType: 'dine-in',
    tableNumber: '',
    paymentMethod: 'cash',
    specialInstructions: ''
  });

  const subtotal = getCartTotal();
  const tax = subtotal * 0.05;
  const total = subtotal + tax - (cart.discount || 0);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (formData.orderType === 'dine-in' && !formData.tableNumber) {
      toast.error('Please enter table number');
      return;
    }
    if (!cart.items || cart.items.length === 0) {
      toast.error('Your cart is empty');
      return;
    }

    try {
      setLoading(true);
      const orderRes = await api.post('/orders', {
        tableNumber: formData.tableNumber ? Number(formData.tableNumber) : undefined,
        orderType: formData.orderType,
        paymentMethod: formData.paymentMethod,
        specialInstructions: formData.specialInstructions
      });

      await api.post('/payments/process', {
        orderId: orderRes.data.order._id,
        paymentMethod: formData.paymentMethod
      });

      await clearCart();
      toast.success('Order placed successfully!');
      navigate(`/track/${orderRes.data.order.orderNumber}`);
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to place order');
    } finally {
      setLoading(false);
    }
  };

  if (!cart.items || cart.items.length === 0) {
    navigate('/cart');
    return null;
  }

  return (
    <div className="max-w-4xl mx-auto px-4 py-8">
      <h1 className="text-3xl font-bold text-dark-800 mb-8">Checkout</h1>

      <form onSubmit={handleSubmit}>
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          <div className="space-y-6">
            <div className="card p-6">
              <h3 className="text-lg font-semibold mb-4">Order Type</h3>
              <div className="grid grid-cols-3 gap-3">
                {[
                  { value: 'dine-in', label: 'Dine In', icon: '🍽️' },
                  { value: 'takeaway', label: 'Takeaway', icon: '🥡' },
                  { value: 'delivery', label: 'Delivery', icon: '🚴' }
                ].map(type => (
                  <button
                    key={type.value}
                    type="button"
                    onClick={() => setFormData({ ...formData, orderType: type.value })}
                    className={`p-4 rounded-lg border-2 text-center transition-all ${
                      formData.orderType === type.value
                        ? 'border-primary-500 bg-primary-50'
                        : 'border-dark-200 hover:border-dark-300'
                    }`}
                  >
                    <span className="text-2xl block mb-1">{type.icon}</span>
                    <span className="text-sm font-medium">{type.label}</span>
                  </button>
                ))}
              </div>
            </div>

            {formData.orderType === 'dine-in' && (
              <div className="card p-6">
                <h3 className="text-lg font-semibold mb-4">Table Number</h3>
                <input
                  type="number"
                  placeholder="Enter table number"
                  value={formData.tableNumber}
                  onChange={(e) => setFormData({ ...formData, tableNumber: e.target.value })}
                  className="input-field"
                  min="1"
                  max="50"
                />
              </div>
            )}

            <div className="card p-6">
              <h3 className="text-lg font-semibold mb-4">Payment Method</h3>
              <div className="space-y-3">
                {[
                  { value: 'cash', label: 'Cash', icon: FiDollarSign },
                  { value: 'card', label: 'Credit/Debit Card', icon: FiCreditCard },
                  { value: 'upi', label: 'UPI', icon: FiSmartphone }
                ].map(method => {
                  const Icon = method.icon;
                  return (
                    <label
                      key={method.value}
                      className={`flex items-center gap-3 p-3 rounded-lg border-2 cursor-pointer transition-all ${
                        formData.paymentMethod === method.value
                          ? 'border-primary-500 bg-primary-50'
                          : 'border-dark-200 hover:border-dark-300'
                      }`}
                    >
                      <input
                        type="radio"
                        name="paymentMethod"
                        value={method.value}
                        checked={formData.paymentMethod === method.value}
                        onChange={(e) => setFormData({ ...formData, paymentMethod: e.target.value })}
                        className="text-primary-500"
                      />
                      <Icon size={20} className="text-dark-500" />
                      <span className="font-medium">{method.label}</span>
                    </label>
                  );
                })}
              </div>
            </div>

            <div className="card p-6">
              <h3 className="text-lg font-semibold mb-4">Special Instructions</h3>
              <textarea
                placeholder="Any special requests or dietary requirements..."
                value={formData.specialInstructions}
                onChange={(e) => setFormData({ ...formData, specialInstructions: e.target.value })}
                className="input-field h-24 resize-none"
              />
            </div>
          </div>

          <div>
            <div className="card p-6 sticky top-24">
              <h3 className="text-lg font-semibold mb-4">Order Summary</h3>

              <div className="space-y-3 mb-4 max-h-64 overflow-y-auto">
                {cart.items.map(item => (
                  <div key={item._id} className="flex justify-between text-sm">
                    <span className="text-dark-600">
                      {item.product?.name} x {item.quantity}
                    </span>
                    <span className="font-medium">₹{(item.product?.price * item.quantity).toFixed(2)}</span>
                  </div>
                ))}
              </div>

              <hr className="my-4" />

              <div className="space-y-2 mb-4">
                <div className="flex justify-between text-dark-600">
                  <span>Subtotal</span>
                  <span>₹{subtotal.toFixed(2)}</span>
                </div>
                <div className="flex justify-between text-dark-600">
                  <span>Tax (5%)</span>
                  <span>₹{tax.toFixed(2)}</span>
                </div>
                {cart.discount > 0 && (
                  <div className="flex justify-between text-green-600">
                    <span>Discount</span>
                    <span>-₹{cart.discount.toFixed(2)}</span>
                  </div>
                )}
                <hr />
                <div className="flex justify-between font-bold text-dark-800 text-xl">
                  <span>Total</span>
                  <span>₹{total.toFixed(2)}</span>
                </div>
              </div>

              <button
                type="submit"
                disabled={loading}
                className="w-full btn-primary py-3 text-lg flex items-center justify-center gap-2"
              >
                {loading ? (
                  'Placing Order...'
                ) : (
                  <>
                    <FiCheck size={20} />
                    Place Order
                  </>
                )}
              </button>
            </div>
          </div>
        </div>
      </form>
    </div>
  );
};

export default Checkout;
